public class TicketBookingService
{
    private readonly EventContext _context;

    public TicketBookingService(EventContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity, string userId)
    {
        if (quantity <= 0)
            return false;

        using var transaction = await _context.Database.BeginTransactionAsync();
        try
        {
            var eventInfo = await _context.Events
                .Where(e => e.Id == eventId)
                .Select(e => new { e.TotalSeats, e.AvailableSeats })
                .FirstOrDefaultAsync();

            if (eventInfo == null || eventInfo.AvailableSeats < quantity)
            {
                await transaction.RollbackAsync();
                return false;
            }

            var updatedSeats = await _context.Events
                .Where(e => e.Id == eventId && e.AvailableSeats >= quantity)
                .ExecuteUpdateAsync(setters => setters
                    .SetProperty(e => e.AvailableSeats, e => e.AvailableSeats - quantity)
                    .SetProperty(e => e.SoldSeats, e => e.SoldSeats + quantity));

            if (updatedSeats == 0)
            {
                await transaction.RollbackAsync();
                return false;
            }

            var ticket = new Ticket
            {
                EventId = eventId,
                UserId = userId,
                Quantity = quantity,
                PurchaseDate = DateTime.UtcNow
            };

            await _context.Tickets.AddAsync(ticket);
            await _context.SaveChangesAsync();
            await transaction.CommitAsync();

            return true;
        }
        catch
        {
            await transaction.RollbackAsync();
            throw;
        }
    }
}